+//! C API for Zell - enables external tools to call back into Zell
+//!
+//! This is used by metal0 when Python code needs to invoke the LLM.
+//! Example Python usage (via ctypes or metal0 bindings):
+//!   result = zell.predict("What is 2+2?")
+//!
+//! Build as shared library: zig build -Dshared
+//! Output: libzell.dylib / libzell.so
+
+const std = @import("std");
+const llama = @import("llama.zig");
+const Scheduler = @import("scheduler.zig").Scheduler;
+
+/// Global state for C API callbacks
+var global_model: ?*llama.Model = null;
+var global_scheduler: ?*Scheduler = null;
+var global_allocator: std.mem.Allocator = std.heap.page_allocator;
+
+// Version info
+const ZELL_VERSION_MAJOR: c_int = 0;
+const ZELL_VERSION_MINOR: c_int = 2;
+const ZELL_VERSION_PATCH: c_int = 0;
+
+/// Initialize Zell with a model file
+/// Returns: 0 on success, negative error code on failure
+///   -1: Memory allocation failed
+///   -2: Failed to load model
+///   -3: Failed to create scheduler
+export fn zell_init(model_path: [*:0]const u8) callconv(.C) c_int {
+    const path = std.mem.sliceTo(model_path, 0);
+
+    // Allocate model
+    global_model = global_allocator.create(llama.Model) catch return -1;
+
+    // Load model
+    global_model.?.* = llama.Model.load(path, .{}) catch {
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        return -2;
+    };
+
+    // Create scheduler
+    global_scheduler = global_allocator.create(Scheduler) catch {
+        global_model.?.deinit();
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        return -1;
+    };
+
+    global_scheduler.?.* = Scheduler.init(global_allocator, global_model.?, .{
+        .max_cells = 4,
+        .context_per_cell = 2048,
+        .enable_tools = false, // Disable tools in C API to avoid recursion
+    }) catch {
+        global_allocator.destroy(global_scheduler.?);
+        global_model.?.deinit();
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        global_scheduler = null;
+        return -3;
+    };
+
+    return 0;
+}
+
+/// Initialize Zell with custom options
+export fn zell_init_with_options(
+    model_path: [*:0]const u8,
+    max_cells: c_int,
+    context_per_cell: c_int,
+) callconv(.C) c_int {
+    const path = std.mem.sliceTo(model_path, 0);
+
+    global_model = global_allocator.create(llama.Model) catch return -1;
+
+    global_model.?.* = llama.Model.load(path, .{}) catch {
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        return -2;
+    };
+
+    global_scheduler = global_allocator.create(Scheduler) catch {
+        global_model.?.deinit();
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        return -1;
+    };
+
+    global_scheduler.?.* = Scheduler.init(global_allocator, global_model.?, .{
+        .max_cells = @intCast(@max(1, max_cells)),
+        .context_per_cell = @intCast(@max(128, context_per_cell)),
+        .enable_tools = false,
+    }) catch {
+        global_allocator.destroy(global_scheduler.?);
+        global_model.?.deinit();
+        global_allocator.destroy(global_model.?);
+        global_model = null;
+        global_scheduler = null;
+        return -3;
+    };
+
+    return 0;
+}
+
+/// Run prediction on a prompt
+/// Returns: Pointer to null-terminated result string, or null on error
+/// Note: Caller must call zell_free_string() on the result
+export fn zell_predict(
+    prompt: [*:0]const u8,
+    max_tokens: c_int,
+) callconv(.C) ?[*:0]u8 {
+    const scheduler = global_scheduler orelse return null;
+    const prompt_slice = std.mem.sliceTo(prompt, 0);
+
+    // Find idle cell
+    const cell_id = scheduler.findIdleCell() orelse return null;
+
+    // Submit prompt
+    scheduler.submit(cell_id, prompt_slice, @intCast(@max(1, max_tokens))) catch return null;
+
+    // Run until complete
+    scheduler.runUntilComplete(4096) catch return null;
+
+    // Get result
+    if (scheduler.getCell(cell_id)) |cell| {
+        const output = cell.getOutput();
+
+        // Allocate null-terminated copy for caller
+        const result = global_allocator.allocSentinel(u8, output.len, 0) catch return null;
+        @memcpy(result[0..output.len], output);
+
+        // Reset cell for reuse
+        cell.reset();
+
+        return result;
+    }
+
+    return null;
+}
+
+/// Free a string returned by zell_predict
+export fn zell_free_string(ptr: ?[*:0]u8) callconv(.C) void {
+    if (ptr) |p| {
+        const len = std.mem.len(p);
+        global_allocator.free(p[0 .. len + 1]);
+    }
+}
+
+/// Check if Zell is initialized
+export fn zell_is_initialized() callconv(.C) bool {
+    return global_model != null and global_scheduler != null;
+}
+
+/// Get the number of available cells
+export fn zell_cell_count() callconv(.C) c_int {
+    const scheduler = global_scheduler orelse return 0;
+    return @intCast(scheduler.cells.len);
+}
+
+/// Get the number of idle cells
+export fn zell_idle_cell_count() callconv(.C) c_int {
+    const scheduler = global_scheduler orelse return 0;
+    var count: c_int = 0;
+    for (scheduler.cells) |*cell| {
+        if (cell.state == .idle) count += 1;
+    }
+    return count;
+}
+
+/// Cleanup Zell and free resources
+export fn zell_deinit() callconv(.C) void {
+    if (global_scheduler) |s| {
+        s.deinit();
+        global_allocator.destroy(s);
+    }
+    if (global_model) |m| {
+        m.deinit();
+        global_allocator.destroy(m);
+    }
+    global_scheduler = null;
+    global_model = null;
+}
+
+/// Get version string
+export fn zell_version() callconv(.C) [*:0]const u8 {
+    return "0.2.0";
+}
+
+/// Get version numbers
+export fn zell_version_major() callconv(.C) c_int {
+    return ZELL_VERSION_MAJOR;
+}
+
+export fn zell_version_minor() callconv(.C) c_int {
+    return ZELL_VERSION_MINOR;
+}
+
+export fn zell_version_patch() callconv(.C) c_int {
+    return ZELL_VERSION_PATCH;
+}

