+const std = @import("std");
+const tools = @import("tools.zig");
+const ToolRequest = tools.ToolRequest;
+const ToolResult = tools.ToolResult;
+
+/// Edgebox configuration
+pub const Config = struct {
+    binary_path: []const u8 = "edgebox",
+    timeout_ms: u32 = 10000,
+    max_output_size: usize = 64 * 1024, // 64KB
+};
+
+var config: Config = .{};
+
+pub fn setConfig(new_config: Config) void {
+    config = new_config;
+}
+
+pub fn getConfig() Config {
+    return config;
+}
+
+/// Execute JavaScript code via edgebox sandbox
+pub fn execute(allocator: std.mem.Allocator, request: ToolRequest) ToolResult {
+    const start_time = std.time.milliTimestamp();
+
+    // Create temp file with JS code
+    const temp_path = "/tmp/zell_edgebox_code.js";
+    const temp_file = std.fs.cwd().createFile(temp_path, .{}) catch |err| {
+        return ToolResult.err(
+            std.fmt.allocPrint(allocator, "Failed to create temp file: {}", .{err}) catch "Failed to create temp file",
+            elapsed(start_time),
+        );
+    };
+    defer temp_file.close();
+
+    temp_file.writeAll(request.payload) catch |err| {
+        return ToolResult.err(
+            std.fmt.allocPrint(allocator, "Failed to write code: {}", .{err}) catch "Failed to write code",
+            elapsed(start_time),
+        );
+    };
+
+    // Run edgebox
+    const result = runProcess(allocator, &[_][]const u8{ config.binary_path, "run", temp_path }, start_time);
+
+    // Clean up temp file
+    std.fs.cwd().deleteFile(temp_path) catch {};
+
+    return result;
+}
+
+/// Run a process and capture output
+fn runProcess(allocator: std.mem.Allocator, argv: []const []const u8, start_time: i64) ToolResult {
+    var child = std.process.Child.init(argv, allocator);
+    child.stdout_behavior = .Pipe;
+    child.stderr_behavior = .Pipe;
+
+    child.spawn() catch |err| {
+        return ToolResult.err(
+            std.fmt.allocPrint(allocator, "Failed to spawn process: {}", .{err}) catch "Failed to spawn process",
+            elapsed(start_time),
+        );
+    };
+
+    // Read stdout using readToEndAlloc
+    const stdout_data = if (child.stdout) |*stdout|
+        stdout.readToEndAlloc(allocator, config.max_output_size) catch ""
+    else
+        "";
+    defer if (stdout_data.len > 0) allocator.free(stdout_data);
+
+    // Read stderr using readToEndAlloc
+    const stderr_data = if (child.stderr) |*stderr|
+        stderr.readToEndAlloc(allocator, config.max_output_size) catch ""
+    else
+        "";
+    defer if (stderr_data.len > 0) allocator.free(stderr_data);
+
+    const term = child.wait() catch |err| {
+        return ToolResult.err(
+            std.fmt.allocPrint(allocator, "Process wait failed: {}", .{err}) catch "Process wait failed",
+            elapsed(start_time),
+        );
+    };
+
+    const time_ms = elapsed(start_time);
+
+    switch (term) {
+        .Exited => |code| {
+            if (code == 0) {
+                return ToolResult.ok(
+                    allocator.dupe(u8, stdout_data) catch "",
+                    time_ms,
+                );
+            } else {
+                var combined: std.ArrayListUnmanaged(u8) = .empty;
+                combined.appendSlice(allocator, stdout_data) catch {};
+                if (stderr_data.len > 0) {
+                    combined.appendSlice(allocator, "\n--- stderr ---\n") catch {};
+                    combined.appendSlice(allocator, stderr_data) catch {};
+                }
+                return .{
+                    .success = false,
+                    .output = combined.toOwnedSlice(allocator) catch "",
+                    .error_msg = std.fmt.allocPrint(allocator, "Process exited with code {}", .{code}) catch "Process failed",
+                    .execution_time_ms = time_ms,
+                };
+            }
+        },
+        .Signal => |sig| {
+            return ToolResult.err(
+                std.fmt.allocPrint(allocator, "Process killed by signal {}", .{sig}) catch "Process killed",
+                time_ms,
+            );
+        },
+        else => {
+            return ToolResult.err("Process terminated abnormally", time_ms);
+        },
+    }
+}
+
+fn elapsed(start_time: i64) u64 {
+    const now = std.time.milliTimestamp();
+    return @intCast(@max(0, now - start_time));
+}
+
+/// Register edgebox handler with tool registry
+pub fn register(registry: *tools.ToolRegistry) void {
+    registry.register(.edgebox, execute);
+}

