+const std = @import("std");
+
+/// Tool types supported by Zell
+pub const ToolType = enum {
+    metal0, // Python code execution via metal0 compiler
+    edgebox, // JavaScript sandbox via edgebox/QuickJS
+    lanceql, // Vector database queries via lanceql
+    shell, // Shell command execution (future)
+};
+
+/// Request to execute a tool
+pub const ToolRequest = struct {
+    tool: ToolType,
+    cell_id: u32,
+    payload: []const u8, // Code or query to execute
+    timeout_ms: u32 = 30000, // Default 30s timeout
+};
+
+/// Result from tool execution
+pub const ToolResult = struct {
+    success: bool,
+    output: []const u8, // Result text to inject into context
+    error_msg: ?[]const u8, // Error message if failed
+    execution_time_ms: u64,
+
+    pub fn ok(output: []const u8, time_ms: u64) ToolResult {
+        return .{
+            .success = true,
+            .output = output,
+            .error_msg = null,
+            .execution_time_ms = time_ms,
+        };
+    }
+
+    pub fn err(msg: []const u8, time_ms: u64) ToolResult {
+        return .{
+            .success = false,
+            .output = "",
+            .error_msg = msg,
+            .execution_time_ms = time_ms,
+        };
+    }
+};
+
+/// Tool handler function signature
+pub const ToolHandler = *const fn (
+    allocator: std.mem.Allocator,
+    request: ToolRequest,
+) ToolResult;
+
+/// Tool Registry - manages available tools and dispatches requests
+pub const ToolRegistry = struct {
+    allocator: std.mem.Allocator,
+    handlers: std.EnumArray(ToolType, ?ToolHandler),
+    enabled: std.EnumArray(ToolType, bool),
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return Self{
+            .allocator = allocator,
+            .handlers = std.EnumArray(ToolType, ?ToolHandler).initFill(null),
+            .enabled = std.EnumArray(ToolType, bool).initFill(false),
+        };
+    }
+
+    /// Register a tool handler
+    pub fn register(self: *Self, tool: ToolType, handler: ToolHandler) void {
+        self.handlers.set(tool, handler);
+        self.enabled.set(tool, true);
+    }
+
+    /// Enable or disable a tool
+    pub fn setEnabled(self: *Self, tool: ToolType, enabled: bool) void {
+        self.enabled.set(tool, enabled);
+    }
+
+    /// Check if a tool is available and enabled
+    pub fn isAvailable(self: *const Self, tool: ToolType) bool {
+        return self.enabled.get(tool) and self.handlers.get(tool) != null;
+    }
+
+    /// Execute a tool request
+    pub fn execute(self: *Self, request: ToolRequest) ToolResult {
+        if (!self.enabled.get(request.tool)) {
+            return ToolResult.err("Tool not enabled", 0);
+        }
+
+        if (self.handlers.get(request.tool)) |handler| {
+            return handler(self.allocator, request);
+        }
+
+        return ToolResult.err("No handler registered for tool", 0);
+    }
+
+    /// Get list of available tools
+    pub fn availableTools(self: *const Self, buffer: []ToolType) []ToolType {
+        var count: usize = 0;
+        for (std.enums.values(ToolType)) |tool| {
+            if (self.isAvailable(tool) and count < buffer.len) {
+                buffer[count] = tool;
+                count += 1;
+            }
+        }
+        return buffer[0..count];
+    }
+};
+
+// Tests
+test "ToolRegistry basic operations" {
