+        fn handle(_: std.mem.Allocator, _: ToolRequest) ToolResult {
+            return ToolResult.ok("test output", 100);
+        }
+    }.handle;
+
+    registry.register(.metal0, dummy_handler);
+    try std.testing.expect(registry.isAvailable(.metal0));
+
+    // Execute request
+    const result = registry.execute(.{
+        .tool = .metal0,
+        .cell_id = 0,
+        .payload = "print('hello')",
+    });
+
+    try std.testing.expect(result.success);
+    try std.testing.expectEqualStrings("test output", result.output);
+}
