+const std = @import("std");
+const tools = @import("tools.zig");
+const ToolType = tools.ToolType;
+
+/// Trigger pattern definition
+pub const TriggerPattern = struct {
+    start_tag: []const u8,
+    end_tag: []const u8,
+    tool: ToolType,
+};
+
+/// Built-in trigger patterns for tool invocation
+pub const TRIGGERS = [_]TriggerPattern{
+    .{ .start_tag = "<RUN>", .end_tag = "</RUN>", .tool = .metal0 },
+    .{ .start_tag = "<PYTHON>", .end_tag = "</PYTHON>", .tool = .metal0 },
+    .{ .start_tag = "<JS>", .end_tag = "</JS>", .tool = .edgebox },
+    .{ .start_tag = "<QUERY>", .end_tag = "</QUERY>", .tool = .lanceql },
+};
+
+/// Detected trigger with extracted content
+pub const DetectedTrigger = struct {
+    tool: ToolType,
+    content: []const u8, // Owned by caller after detection
+    tag_name: []const u8, // e.g., "RUN", "PYTHON", "JS", "QUERY"
+};
+
+/// State machine for detecting tool triggers in token stream
+pub const TriggerDetector = struct {
+    buffer: std.ArrayListUnmanaged(u8),
+    state: State,
+    current_trigger: ?*const TriggerPattern,
+    content_start: usize,
+    allocator: std.mem.Allocator,
+
+    const State = enum {
+        scanning, // Looking for start tag
+        in_tag, // Found start, accumulating until end tag
+    };
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return .{
+            .buffer = .empty,
+            .state = .scanning,
+            .current_trigger = null,
+            .content_start = 0,
+            .allocator = allocator,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.buffer.deinit(self.allocator);
+    }
+
+    /// Reset detector state (call after handling a trigger)
+    pub fn reset(self: *Self) void {
+        self.buffer.clearRetainingCapacity();
+        self.state = .scanning;
+        self.current_trigger = null;
+        self.content_start = 0;
+    }
+
+    /// Feed a token string to the detector.
+    /// Returns DetectedTrigger if a complete trigger is found.
+    /// Caller owns the returned content slice (must free with allocator).
+    pub fn feed(self: *Self, token: []const u8) !?DetectedTrigger {
+        try self.buffer.appendSlice(self.allocator, token);
+
+        switch (self.state) {
+            .scanning => {
+                // Check for any start tag
+                for (&TRIGGERS) |*trigger| {
+                    if (std.mem.indexOf(u8, self.buffer.items, trigger.start_tag)) |pos| {
+                        self.state = .in_tag;
+                        self.current_trigger = trigger;
+                        self.content_start = pos + trigger.start_tag.len;
+                        // Check if end tag is already in buffer
+                        return try self.checkForEndTag();
+                    }
+                }
+            },
+            .in_tag => {
+                return try self.checkForEndTag();
+            },
+        }
+        return null;
+    }
+
+    fn checkForEndTag(self: *Self) !?DetectedTrigger {
+        if (self.current_trigger) |trigger| {
+            if (std.mem.indexOf(u8, self.buffer.items[self.content_start..], trigger.end_tag)) |rel_end_pos| {
+                const end_pos = self.content_start + rel_end_pos;
+                const content = self.buffer.items[self.content_start..end_pos];
+
+                // Allocate and copy content for caller
+                const owned_content = try self.allocator.dupe(u8, content);
+
+                // Extract tag name (e.g., "RUN" from "<RUN>")
+                const tag_name = trigger.start_tag[1 .. trigger.start_tag.len - 1];
+
+                const result = DetectedTrigger{
+                    .tool = trigger.tool,
+                    .content = owned_content,
+                    .tag_name = tag_name,
+                };
+
+                self.reset();
+                return result;
+            }
+        }
+        return null;
+    }
+
+    /// Check if detector is currently inside a tag
+    pub fn isInTag(self: *const Self) bool {
+        return self.state == .in_tag;
+    }
+
+    /// Get currently accumulated buffer (for debugging)
+    pub fn getBuffer(self: *const Self) []const u8 {
+        return self.buffer.items;
+    }
+
+    /// Free a detected trigger's content
+    pub fn freeContent(self: *Self, content: []const u8) void {
+        self.allocator.free(content);
+    }
+};
+
+// Tests
+test "TriggerDetector detects RUN tag" {
+    const allocator = std.testing.allocator;
+
+    var detector = TriggerDetector.init(allocator);
+    defer detector.deinit();
+
+    // Feed tokens one at a time
+    try std.testing.expect((try detector.feed("<")) == null);
+    try std.testing.expect((try detector.feed("RUN")) == null);
+    try std.testing.expect((try detector.feed(">")) == null);
+
+    try std.testing.expect(detector.isInTag());
+
+    try std.testing.expect((try detector.feed("print('hello')")) == null);
+    try std.testing.expect((try detector.feed("</")) == null);
+    try std.testing.expect((try detector.feed("RUN")) == null);
+
+    const result = try detector.feed(">");
+    try std.testing.expect(result != null);
+
+    const trigger = result.?;
+    defer allocator.free(trigger.content);
+
+    try std.testing.expect(trigger.tool == .metal0);
+    try std.testing.expectEqualStrings("print('hello')", trigger.content);
+    try std.testing.expectEqualStrings("RUN", trigger.tag_name);
